var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안, 수녀님…….","JPN":"ごめん、シスター……","ENG":"Sorry, Sister...","TWN":"抱歉，修女……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아? 어디 다치지는 않았어?","JPN":"大丈夫？　怪我はない？","ENG":"Are you okay? You're not hurt, are you?","TWN":"你還好嗎？沒受傷吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"아아, 네. 괜찮습니다…….","JPN":"ああ、はい。大丈夫です……","ENG":"Ah, yes. I'm fine...","TWN":"啊，沒事，我沒事……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 갑자기 왜 멈춰? 이제 술래잡기 끝이야?","JPN":"どうした、いきなり止まっちゃって？　もう鬼ごっこは終わり？","ENG":"Huh? Why'd you suddenly stop? Is our little game of tag already over?","TWN":"咦？你怎麼突然停下？我們的捉迷藏結束了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"신경 꺼. 골목에서 수녀님이랑 부딪친 것뿐이니까.","JPN":"何でもない。路地でシスターとぶつかっただけ。","ENG":"Mind your own business. I just bumped into a nun in the alley.","TWN":"不關你的事。我只是剛好在巷子裡撞到一個修女。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐? 수녀님?","JPN":"は？　シスター？","ENG":"Huh? A nun?","TWN":"咦？修女？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너는 저게 어딜 봐서 수녀라는 거야?","JPN":"あれのどこがシスターだって言うんだ？","ENG":"Which part of her looks like a nun to you?","TWN":"她哪裡看起來像修女了？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だって？","ENG":"What did you just say?","TWN":"什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"앗, 거울이……!","JPN":"あっ、鏡が……！","ENG":"Ah, my mirror...!","TWN":"啊，我的鏡子……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"당신들은 누구죠……?","JPN":"あなたたちは誰ですか……？","ENG":"Who are you...?","TWN":"你是……？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너는……?","JPN":"あなた……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_QM","text":{"KOREA":"꺄악……!","JPN":"きゃっ……！","ENG":"Kyaaaah...!","TWN":"呀啊！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미, 너! 자꾸 이럴래? 진정하라고 했잖아!","JPN":"エイミー！　いいかげんにして！　落ち着きなって！","ENG":"Amy! Seriously?! I told you to calm down!","TWN":"艾米，你是認真的嗎？！我不是叫你冷靜一點嗎！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워, 유미나! 지금 저걸 보고 진정하라고……!?","JPN":"うるさい、ミナ！　あれを見て落ち着けって……！？","ENG":"Shut it, Yoo Mina! You expect me to calm down after seeing that?!","TWN":"吵死了，劉米娜！你叫我看到那種情況還能冷靜下來嗎？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"네가 누굴 감싸 준 지 알기나 해?","JPN":"あんたが誰をかばってるのかわかってんの？","ENG":"Do you even know who you're defending right now?","TWN":"你知道你現在到底在袒護誰嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"누가 봐도 거기 있는 그년이 <color=#ffd34c>스완</color>이잖아……!","JPN":"誰がどう見ても、その女が<color=#ffd34c>スワン</color>だろ……！","ENG":"Anyone can see that brat over there is <color=#ffd34c>Swan</color>...!","TWN":"誰都能看出來那邊的那個女人是<color=#ffd34c>史旺</color>……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리야? 얘가 스완이라고?","JPN":"どういうこと？　この子がスワン？","ENG":"What are you talking about? You're saying that's Swan?","TWN":"什麼意思？她是史旺？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"확실히… 닮긴 했지만, 내가 아는 스완은 얘보다 훨씬 어른이었던 거 같은데……?","JPN":"確かに……似てはいるけど、私の知ってるスワンはこの子よりずっと大人だった気が……？","ENG":"She does look familiar... but the Swan I knew was way more of an adult than this...","TWN":"確實……雖然有點像，但我認識的史旺好像比她成熟多了……？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_QM","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아, 답답하게 구네, 진짜로!","JPN":"ああ、イライラさせてくれる、マジで！","ENG":"Ugh, you're seriously testing my patience!","TWN":"哎，真是的，真讓人著急！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"방금 못 봤어? 스완이 거울로 모습을 위장하고 있었잖아!","JPN":"今の見てなかったの？　スワンが鏡で姿を変えてたじゃん！","ENG":"Did you not just see that? Swan used a mirror to disguise herself!","TWN":"你沒看到嗎？史旺剛才用鏡子偽裝了自己！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저렇게 모습을 바꾸고 다른 사람인 척, 연기하는 게 저 망할 년의 주특기라고!","JPN":"ああやって姿を変えて他人みたいに演技するのが、あのクソ女の得意技なんだ！","ENG":"Changing her appearance and pretending to be someone else is exactly that damn woman's specialty!","TWN":"改變外貌、假扮成別人，正是那個該死女人的拿手好戲！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐만요! 주특기라니요!","JPN":"ま、待ってください！　得意技だなんて！","ENG":"W-wait a minute! What do you mean, my specialty?!","TWN":"等、等一下！什麼拿手好戲！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 파노라마를 써서 변장을 한 건 사실이지만… 이건 다 사정이 있어서 그렇다고요……!","JPN":"私がパノラマで変装したのは事実ですけど……これには事情があります……！","ENG":"Yes, I did use Panorama to disguise myself... but I had my reasons...!","TWN":"沒錯，我確實用了全景來偽裝自己……但我是有我的理由的……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 망할 년이라니…! 저를 언제 본 적이 있다고 그런 막말을 하시는 거죠?","JPN":"それに、クソ女だなんて……！　私と初対面なのに、どうしてそんな言い方をするのですか？","ENG":"And calling me a damn woman...?! Why are you talking about me like we've met me before?!","TWN":"還有，叫我該死的女人……？！你幹嘛一副好像以前見過我的口氣？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 한 번 본 사람을 잊지 않아요. 당신 같은 사람은 오늘 처음 본다고요!","JPN":"私は一度会った人は忘れません。あなたみたいな人は今日初めて会いました！","ENG":"I never forget a face. And I'm seeing yours for the first time today!","TWN":"我從不會忘記一張臉。而我今天可是第一次見到你！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하긴, 그런 천박한 옷차림에 상스러운 문신을 새긴 여자라면 누구라도 잊을 수 없겠지만……!","JPN":"まあ、そのようにだらしない服装に下品なタトゥーをしている女なら、私でなくても忘れられないでしょうけど……！","ENG":"I'd never forget someone dressed so trashy with those vulgar tattoos...!","TWN":"我怎麼可能忘掉一個穿得這麼廉價、身上還有那些低俗刺青的人……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭, 그래도 한솥밥 먹던 식구였는데, 섭섭한데?","JPN":"くくっ、かつては同じ六翼の仲間だったのに、つれないな。","ENG":"Keke, come on, we used to share the same table. Your words hurt.","TWN":"呵呵，別這樣嘛，我們以前可是同桌吃過飯的，你這話可真傷人。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 우리를 배신하고 나한테 칼침을 놨던 사람이 누구였더라?","JPN":"じゃあこっちを裏切って、あたしをナイフで刺したのはどこの誰だったのかな？","ENG":"So tell me, who was it that betrayed us and stabbed me in the back?","TWN":"那你倒是告訴我，當初是誰背叛了我們、又在背後捅了我一刀？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"배신? 칼침이라고요? 제가요?","JPN":"裏切る？　ナイフ？　私が？","ENG":"Betrayed? Stabbed? Me?","TWN":"背叛？捅你？是我？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요. 아무래도 사람을 착각하신 것 같네요.","JPN":"どうでしょう。人違いだと思いますよ。","ENG":"No idea. You must have mistaken me for someone else.","TWN":"我想你可能認錯人了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 배우랍니다. 식사용 나이프 외에는 제대로 된 칼을 쥐어 본 적도 없는 걸요?","JPN":"私は俳優です。食事用のナイフ以外に刃物らしい刃物を握ったことはありませんから。","ENG":"I'm an actress, you know. The only knife I've ever held is a dinner knife.","TWN":"我是個演員。除了餐刀以外，我還從來沒有拿過真正的刀呢。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 칼로 사람을 찌르다니… 제가 무슨 심야의 살인마도 아니고…….","JPN":"ましてやナイフで人を刺すなんて……深夜の殺人鬼でもないのに……","ENG":"Stabbing someone with a knife... what am I, the Midnight Killer...?","TWN":"更何況用刀刺人……我又不是午夜殺人魔……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"심야의 살인마라고……?","JPN":"深夜の殺人鬼……？","ENG":"The Midnight Killer...?","TWN":"午夜殺人魔？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미, 뭔가 이상해.","JPN":"エイミー、何か変だよ。","ENG":"Amy, something's off.","TWN":"艾米，感覺有些不太對勁。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴 스완의 세계라면서? 아무런 이유 없이 갑자기 스완이 우리 앞에 나타날 리 없잖아?","JPN":"ここはスワンの世界でしょ？　何の理由もなく、いきなりスワンが私たちの前に現れるはずがないよ。","ENG":"This is Swan's world, right? Then there's no reason for her to just pop up in front of us like this.","TWN":"這裡是史旺的世界對吧？史旺不可能無緣無故突然出現在我們面前吧？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 모습이 위장이라고 해도, 뭐 하러 자기 어린 모습으로 위장한다는 거야?","JPN":"あの姿が偽装だとしても、どうして自分の小さい頃の姿に偽装するの？","ENG":"Even if it's a disguise, why would she disguise herself as a younger version of herself?","TWN":"即使那副模樣是偽裝，為什麼要偽裝成自己小時候的樣子呢？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아까부터 자꾸 같은 말 반복하게 하지 마, 유미나!","JPN":"さっきから同じことを言わせないで、ミナ！","ENG":"Quit making me repeat myself, Yoo Mina!","TWN":"別讓我一直重複同樣的話，劉米娜！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"우린 놀러 온 게 아니야. 수단과 방법을 가리지 않고, 스완의 행방을 쫓아야 한다고!","JPN":"あたしらは遊びに来たんじゃない。なりふり構わずスワンの行方を追わないと！","ENG":"We're not here on vacation. We have to track down Swan, whatever it takes!","TWN":"我們不是來玩的。無論用什麼手段，都要追查到史旺的下落！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 망할 년이 손에 넣은 세피라를 되돌리지 않으면, 되려 우리 세계가 위험할지도 몰라!","JPN":"あのクソ女が手に入れたセフィラを元に戻さないと、あたしらの世界が危険になるかもしれない！","ENG":"If we don't take back the Sephira that wench stole, our own world might be in danger!","TWN":"如果不把那個該死的女人手中的生命樹奪回來，反而可能會危及我們的世界！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"이런 인적 드문 골목에서 무슨 소란인가 했더니…….","JPN":"こんな人気のないところで何の騒ぎかと思ったら……","ENG":"Such a ruckus in a quiet alley...","TWN":"我說這種人跡罕至的小巷裡，怎麼還有騷動……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_QM","text":{"KOREA":"아무래도 내 파트너가 무슨 실례를 범한 모양이군.","JPN":"どうやら私のパートナーが失礼したようだ。","ENG":"It seems my partner may have caused you some trouble.","TWN":"看來我的搭檔似乎犯了什麼無禮的行為。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너는……!?","JPN":"あんたは……！？","ENG":"You are...?!","TWN":"你是……！？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완의 파트너라고……?","JPN":"スワンのパートナーだって……？","ENG":"Swan's partner...?","TWN":"史旺的搭檔？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"파, 파트너라니……!","JPN":"ぱ、パートナーだなんて……！","ENG":"P-partner...?!","TWN":"搭，搭檔……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 밖에서 그런 소리 하지 말라고 했잖아요, 애버라인!","JPN":"外ではそういうこと言わないでって言ったではないですか、アバーライン！","ENG":"I told you not to say that in public, Abberline!","TWN":"我不是告訴過你不要在外面說這種話嗎？艾伯林！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 런던 제일의 프리마돈나라고요! 스캔들이라도 나면 어쩌려고……!","JPN":"私はロンドン一のプリマドンナです！　スキャンダルにでもなったらどうするのですか……！","ENG":"I'm the top prima donna in London! What if it turns into a scandal...?!","TWN":"我是倫敦最出色的首席女主角！要是出了醜聞該怎麼辦……！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 무례를 용서하게, 스완","JPN":"ふふ、失礼。スワン。","ENG":"Haha, forgive my rudeness, Swan.","TWN":"呵呵，請原諒我的無禮，史旺"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 두 사람 모두 무기를 내려놓고, 함께 커피라도 한잔하는 게 어떻겠나?","JPN":"2人とも武器を下ろして、一緒にコーヒーでもいかがかね？","ENG":"Now, why don't we all put the weapons down and enjoy a cup of coffee together?","TWN":"你們兩個人都放下武器，一起喝杯咖啡怎麼樣？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다른 세계로부터 온 이방인들이여…….","JPN":"別の世界から来た異邦人たち……","ENG":"Outsiders from another world...?","TWN":"從其他世界來的外邦人啊……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 22일. 평행 세계 런던, <color=#ffd34c>베이커 가 211번지</color>","JPN":"1888年10月22日｡パラレルワールドのロンドン、<color=#ffd34c>ベーカー街211番地</color>","ENG":"October 22, 1888, Parallel World London, <color=#ffd34c>211 Baker St.</color>","TWN":"1888年10月22日。平行世界倫敦，<color=#ffd34c>貝克街211號</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……말도 안 돼.","JPN":"……嘘でしょ。","ENG":"...No way.","TWN":"……這不可能。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 여기가 정말로 1888년의 런던이라는 거야?","JPN":"じゃあ、ここは本当に1888年のロンドンってこと？","ENG":"So this really is London in 1888?","TWN":"那麼，這裡真的是1888年的倫敦嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 저 이상한 도구들도 그렇고, 왠지 내가 알고 있는 런던이랑은 다른 것 같은데?","JPN":"でもあの変な道具もそうだし、なんだか私の知っているロンドンとは違うみたいだけど。","ENG":"But those weird devices and all. This place doesn't feel like the London I know?","TWN":"但是那些奇怪的工具，還有總覺得和我所知道的倫敦不太一樣呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군…….","JPN":"そうだな……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이야기를 종합하면, 아무래도 자네들의 세계와 우리 세계는 다른 역사를 가진 모양이야.","JPN":"話をまとめると、どうやら君たちの世界と私たちの世界は違う歴史を持っているようだ。","ENG":"Judging from everything you've said, it seems your world and ours have followed different histories.","TWN":"綜合來看，你們的世界和我們的世界似乎有著不同的歷史。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면, 이건 분기로 나뉘어진 <color=#ffd34c>평행 세계</color>일지도 모르겠군.","JPN":"なら、これは分岐によって分かれた<color=#ffd34c>パラレルワールド</color>なのかもしれないな。","ENG":"Which would mean that this might be a <color=#ffd34c>parallel world</color>, split from a different branch.","TWN":"那麼，這可能是被分成<color=#ffd34c>平行世界</color>的分支。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"평행 세계라고……?","JPN":"パラレルワールド……？","ENG":"A parallel world...?","TWN":"平行世界……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만요! 이야기를 전혀 못 따라가겠다고요!","JPN":"待ってください！　話にまったく追いつけません！","ENG":"Wait just a second! I'm completely lost over here!","TWN":"等等！我完全跟不上你說的話！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 이 사람들이 정말로 다른 세계에서 온 이방인이라는 건가요?","JPN":"では、この人たちが本当に別の世界から来た異邦人だというのですか？","ENG":"Are you saying these people are actually outsiders from another world?","TWN":"那麼，這些人真的是來自其他世界的外邦人嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완, 자네는 아직 관찰력이 부족해.","JPN":"スワン、君はまだ観察力が足りないな。","ENG":"Swan, your observational skills are still lacking.","TWN":"史旺，你的觀察力還不夠。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"파격적인 디자인은 그렇다고 해도, 두 사람의 의상은 재질이 전혀 다르지 않나?","JPN":"破格的なデザインはともかく、2人の衣装は材質がまったく違う。","ENG":"Even if you set aside the unconventional designs, look at the material of their clothing. It's completely different, no?","TWN":"就算是設計很大膽，但兩個人的服裝材質也完全不同的，不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 두 사람이 지니고 있는 장비 또한 처음보는 형태야.","JPN":"2人の持つ装備もまた見たことのない形だ。","ENG":"And the gear they carry, too. I've never seen anything like it.","TWN":"而且這兩人攜帶的裝備也是我第一次見到的形態。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한눈에 봐도 황실의 제식 장비보다 몇 세기 이상 발전한 무기가 틀림없어.","JPN":"どう見ても皇室の制式装備より何世紀も発展した武器に違いない。","ENG":"At a glance, their weapons are clearly centuries ahead of the standard issue gear of the Royal Guard.","TWN":"一眼就能看出這武器比皇室的制式裝備先進了幾個世紀。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그 정도는 저도 알고 있다고요…! 그냥 믿지 못했을 뿐이지……!","JPN":"そ、それくらいは私にもわかります……！　だた信じられなかっただけで……！","ENG":"W-well, I noticed that much too...! I just couldn't bring myself to believe it......!","TWN":"我，我也知道！只是我不敢相信而已……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만…! 그러고보니 당신은 어떻게 그렇게 무덤덤할 수가 있는 거죠……?","JPN":"待ってください……！　そういえば、あなたはどうしてそんなに平然としていられるのですか……？","ENG":"Wait a minute...! How are you so calm about all this...?","TWN":"等等！？說回來，你怎麼能如此冷靜？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저 사람들이 다른 세계에서 온 사람들이라면서요?","JPN":"あの人たちは、異世界より来たのでしょう？","ENG":"You're saying they're really from another world?","TWN":"你不是說那些人是從其他世界來的人嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 간단한 이야기일세, 스완.","JPN":"ふふ、簡単な話だ。スワン。","ENG":"Haha, it's simple really, Swan.","TWN":"呵呵，這是個簡單的故事，史旺。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 전에도 다른 세계로부터 온 이방인을 만난 적이 있거든.","JPN":"私は前にも異世界から来た異邦人に会ったことがある。","ENG":"This isn't the first time I've met outsiders from another world.","TWN":"我以前也遇到過來自其他世界的外邦人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"네에……?","JPN":"はい……？","ENG":"W-what...?","TWN":"什麼……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 당신 설마 우리 말고 다른 엑자일러를 만난 적이 있다고?","JPN":"ちょっと、あなた、まさか私たち以外にエグザイラーに会ったことがあるの？","ENG":"Wait, are you saying you've met other Exiles besides us?","TWN":"等一下，你該不會是見過除了我們以外的其他流浪者吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"액자일러라… 자네들은 그런 식으로 부르는 모양이군.","JPN":"エグザイラ―か……君たちはそのような名前で呼んでいるのかね？","ENG":"Exiles...? So that's what you call yourselves.","TWN":"流浪者嗎？？看來你們是這樣稱呼的啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건, 이 세계에 마석이 나타난 지 얼마 지나지 않은 시점이었어.","JPN":"あれは、この世界に魔石が現れて間もない頃だった。","ENG":"It was shortly after Mana Stones first began appearing in this world.","TWN":"那是在這個世界出現魔石不久之後的事情。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 처음에는 믿지 않았지. 그 이방인의 말은 너무나 허황된 것들이었거든.","JPN":"もちろん、最初は信じられなかった。その異邦人の話は突拍子もないことばかりだったからな。","ENG":"Naturally, I didn't believe it at first. The claims that outsider made were utterly absurd.","TWN":"當然，一開始我是不相信的。那個外邦人的話實在是太荒謬了。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 나와 파트너는 여러 사건들을 해결해가면서…….","JPN":"だが、パートナーと様々な事件を解決していく中で……","ENG":"But as my partner and I solved case after case...","TWN":"但是我和搭檔在解決各種事件的過程中……"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리가 살고 있는 이 세계에 이성과 상식 밖의 <color=#ffd34c>어떤 법칙</color>이 존재한다는 것을 깨닫게 되었네.","JPN":"私たちが暮らしているこの世界に、理性と常識を逸脱した<color=#ffd34c>ある法則</color>が存在しているという事実に気づいたんだ。","ENG":"We came to understand that our world operates under <color=#ffd34c>laws</color> beyond reason and common sense.","TWN":"我們生活的這個世界中，存在著超越理性和常識的<color=#ffd34c>某種法則</color>。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 이를 테면 마석과 이능력자, 증표…….","JPN":"そう、たとえば魔石と異能力者、印……","ENG":"Things like Mana Stones, supernaturals, and marks......","TWN":"是的，比如魔石、超能力者、印記……"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 평행 세계의 존재 역시 그자가 말했던 세계를 만드는 법칙의 일부라고 할 수 있겠지.","JPN":"そしてパラレルワールドの存在もまた、あの者が言っていた世界を作る法則の一部だと言えるだろう。","ENG":"And the existence of parallel worlds too was part of the law of creating a world that outsider spoke of.","TWN":"而且，平行世界的存在，也可以說是他所說的創造世界的法則的一部分吧。"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"세계를 만드는 법칙……?","JPN":"世界を作る法則……？","ENG":"The law of creating a world...?","TWN":"創造世界的法則？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 평행 세계마다 어떤 공통점이 있다는 거야?","JPN":"じゃあ、パラレルワールドごとに、何か共通点があるってこと？","ENG":"So there's some kind of common thread across all these parallel worlds?","TWN":"那麼說，每個平行世界之間有什麼共同點嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마석이라는 건, 이터니움인 것 같고… 이능력자라는 건 카운터를 말하는 것 같은데…….","JPN":"魔石っていうのはエタニウムのようだし……異能力者はカウンターのことを指しているんだと思うけど……","ENG":"Mana Stones sound like Eternium... and supernaturals probably mean Counters......","TWN":"所謂的魔石，似乎是永恆之金……所謂的超能力者，似乎是制裁者……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 같은 개념이라도 각 세계마다 명칭의 차이가 있다는 점은 꽤 흥미롭군.","JPN":"ふふ、同じ概念でも世界が違えば名称も違うというのはなかなか興味深いな。","ENG":"Haha, it's fascinating how the same concepts can go by different names across worlds.","TWN":"呵呵，即使是相同的概念，每個世界的名稱差異也相當有趣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기회가 된다면, 자네들의 세계에 가보고 싶어졌어.","JPN":"機会があれば、君たちの世界に行ってみたいものだ。","ENG":"If I ever get the chance, I'd love to visit your world someday.","TWN":"如果有機會，我也想去你們的世界看看。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그렇다고 해도 역시 인정할 수 없네.","JPN":"だが、そうだとしてもやはり認めることはできない。","ENG":"Still, even with all that, I just can't accept it.","TWN":"但即便如此，我還是無法接受。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네들의 말대로라면, 이 세계는 한 차례 멸망한 뒤 다시 원래대로 돌아왔다는 뜻이야.","JPN":"君たちの話どおりだすると、この世界は一度滅亡した後にまた元どおりに戻ったということになる。","ENG":"If what you say is true, then this world was once destroyed and somehow returned to its original state.","TWN":"照你們所說，這個世界在經歷了一次滅亡後又恢復了原樣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"쏟아진 물은 주워 담을 수 없어. 차갑게 식어버린 커피는 저절로 뜨거워지지 않지.","JPN":"覆水盆に返らず。冷めてしまったコーヒーが勝手に温まることはない。","ENG":"But you can't unspill water. And cold coffee doesn't get hot again on its own.","TWN":"潑出去的水是收不回來的。冷掉的咖啡也不會自己變熱。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"엔트로피의 역전은 불가능해. 그건 틀림없이 세계를 만드는 법칙에 위배된 일일 테니까.","JPN":"エントロピーの逆転は不可能だ。それはきっと世界を作る法則に反することだろうからな。","ENG":"Reversing entropy is impossible. That would clearly violate the law of creating a world.","TWN":"熵的逆轉是不可能的。那無疑是違反了創造世界的法則。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 나는 아직 사건을 포기하지 않았네.","JPN":"何より、私はまだ事件を諦めてはいない。","ENG":"More than anything, I haven't given up on the case.","TWN":"最重要的是，我還沒有放棄這個事件。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계가 임계치에 다다르긴 했지만, 그렇다고 아직 멸망하지는 않았어.","JPN":"この世界は臨界値に達してはいるが、まだ滅んではいない。","ENG":"This world may be approaching its limit, but it hasn't perished yet.","TWN":"這個世界雖然已經達到了臨界點，但還沒有毀滅。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 우리가 이렇게 살아있는 것 자체가 그 증거 아닌가?","JPN":"今私たちがこうやって生きていること自体がその証拠ではないかね？","ENG":"The very fact that we're all still breathing here is proof enough, isn't it?","TWN":"我們現在活著，這本身就是證據，不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"개소리 집어치워, 탐정.","JPN":"ふざけんなよ、探偵。","ENG":"Cut the crap, detective.","TWN":"別再說廢話了，偵探。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나는 이미 이 세계의 말로를 알고 있어. 이 세계는 이미 진즉에 멸망했다고.","JPN":"あたしはすでにこの世界の末路を知ってる。この世界はとっくに滅亡したんだ。","ENG":"I already know how this world ends. It's been doomed for a long time now.","TWN":"我已經知道這個世界的結局。這個世界早就已經滅亡了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"말로를 알고 있다? 그거 재미있군.","JPN":"末路を知っている？　それは面白い。","ENG":"You know how it ends? Now that's interesting.","TWN":"你知道結局？真有意思。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러고 보니 내가 탐정이라는 건, 자네들에게 아직 밝히지 않았는데 말이지.","JPN":"そういえば私が探偵だということは、君たちにまだ話していなかったはずだが。","ENG":"Funny how I haven't even told you that I'm a detective yet.","TWN":"說起來，我還沒告訴你們我是偵探呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"탐정, 네 녀석의 존재에 대해서는 내 동료로부터 질리도록 들었어.","JPN":"探偵、あんたについてなら、仲間から飽きるほど聞いた。","ENG":"Detective, huh? I've heard more than enough about you from my partner.","TWN":"偵探，是吧？我已經從我的搭檔那裡聽了不少關於你的事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그리고 네가 스완이랑 물고 빨고 하던 사이라는 것도 알고 있지.","JPN":"あんたがスワンとちちくりあう仲だってことも知ってる。","ENG":"And I know you and Swan used to be all over each other.","TWN":"而且我知道你和史旺以前可是形影不離。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼, 스완이 이 세계를 다시 되돌린 것도 널 구하기 위해서 아니었을까?","JPN":"スワンがこの世界を元に戻したのもあんたを助けるためだったんじゃないの？","ENG":"So maybe the reason she restored the world was to save you?","TWN":"所以，也許她恢復世界的理由，就是為了救你？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무, 무, 무, 무, 무, 물고 빨고 하던 사이……!?","JPN":"ちちちち、ちちくりあう仲ですって……！？","ENG":"A-a-all over each other...?!","TWN":"形、形影不離……？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어쩜 그렇게 천박한 말을 아무렇지도 않게 할 수 있는 거죠……!","JPN":"どうしてそんな下品な言葉を平気で言えるのかしら……！","ENG":"How can you spout something so vulgar with a straight face...?!","TWN":"你怎麼能一臉正經地說出這麼下流的話……？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"누가 그런 헛소문을 퍼트리는 건가요! 당신들의 세계는 다 저런 무례한 인간들뿐인가요……!","JPN":"誰がそんな噂を広めているの！？　あなたたちの世界の人はみんなそのように無礼なのですか……！","ENG":"Who's spreading such nonsense?! Is your world full of rude people like her...?!","TWN":"是誰在散播這種胡言亂語！你們的世界是不是都像她這麼沒禮貌的人啊……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하하… 다 그런 건 아닌데 말이지…….","JPN":"はは……みんながそうではないけどね……","ENG":"Haha... not all of them, but yeah...","TWN":"哈哈……也不是全都那樣的……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이게 다 당신 때문이에요! 당신이 날 파트너라고 부르니까, 저 사람들이 오해하잖아요!","JPN":"全部あなたのせいです！　あなたが私のことをパートナーなどと呼ぶから、あの人たちが誤解するんです！","ENG":"This is all your fault! You're the one who called me your partner, and now everyone's misunderstanding!","TWN":"這都是因為你！因為你叫我搭檔，那些人才會誤會！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"빨리 부정해요!","JPN":"早く否定してください！","ENG":"Deny it. Now!","TWN":"你快點否認！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 제법 흥미로운 이야기야.","JPN":"ふふ、なかなか興味深い話だ。","ENG":"Haha... Quite the tale.","TWN":"呵呵，真是個有趣的故事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 하고 싶은 말이 뭐지, 킬 미 레이디?","JPN":"それで？　何が言いたいのかな、キル・ミー・レディー？","ENG":"So? What's your point, Kill Me Lady?","TWN":"所以呢？你想說什麼？殺手小姐？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"부정하라고……!","JPN":"否定しなさいって……！","ENG":"I said deny it...!","TWN":"你快點否認……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭘 시치미 떼고 앉았어? 그럼 뻔하잖아?","JPN":"何とぼけてんの？　決まってるじゃん？","ENG":"Quit playing dumb. It's obvious, isn't it?","TWN":"你裝什麼？這不是顯而易見的嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 망할 년이 자기 세계를 되돌리는 데 성공했다면, 가장 먼저 널 찾아왔겠지, 탐정.","JPN":"あのクソ女が自分の世界を元に戻すことに成功したら、真っ先にあんたを訪ねてきたはずさ、探偵。","ENG":"If that damn woman really did turn back time, the first person she'd run to is you, detective.","TWN":"那個該死的女人如果成功恢復了她的世界，首先就會來找你，偵探。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"세계가 멸망해 버려 만나지 못하게 된 연인을 만나고 싶을 테니까 말이야.","JPN":"世界が滅亡して会えなくなった恋人に会いたかったはずだからね。","ENG":"After all, she'd want to see the lover she lost when the world was restored.","TWN":"因為想要見到因世界毀滅而無法相見的戀人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그렇다면 역시 스완은 너와 가장 가까운 곳에 숨어있지 않겠어?","JPN":"だとしたら、スワンはあんたのもっとも近いところに隠れてる可能性がある。","ENG":"So it makes sense she'd be hiding somewhere close to you, right?","TWN":"這麼說的話，史旺肯定會藏在離你最近的地方不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그리고 어쩌면 탐정, 너도 한패라서 그 망할 년을 감싸주고 있는 걸지도 모르지.","JPN":"それに探偵、あんたもグルになってあのクソ女をかばってるのかもしれない。","ENG":"And maybe you're in it too, helping that damn woman stay hidden.","TWN":"而且說不定你這個偵探也是一夥的，所以才會包庇那個該死的女人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"바로 지금처럼.","JPN":"今みたいにね。","ENG":"Just like you're doing now.","TWN":"就像現在這樣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"과연 설득력이 있군.","JPN":"なるほど、説得力があるな。","ENG":"That theory does hold some weight.","TWN":"果然很有說服力。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 가설을 증명할 방법이 있나?","JPN":"だが、その仮説を証明する方法はあるのかね？","ENG":"But can you prove it?","TWN":"但是，你有辦法證明這個假設嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"증명? 웃기고 자빠졌네.","JPN":"証明？　ふざけんなよ。","ENG":"Prove it? Don't make me laugh.","TWN":"證明？真是可笑至極。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"지금 뭔가 착각하고 있는 것 같은데, 탐정 나리.","JPN":"なんか勘違いしてるみたいだけど、探偵の旦那。","ENG":"Seems you've got it twisted, detective darling.","TWN":"偵探先生，你好像是有什麼誤會？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"증명을 해야 하는 건, 이쪽이 아니라 그쪽이라고? 지금 너희들이 어떤 입장인 지 알려줘?","JPN":"証明しないといけないのは、こっちじゃなくてそっち。今あんたらがどんな立場にあるのか教えてあげようか？","ENG":"You're the ones who need to prove yourselves. Should I remind you where you stand right now?","TWN":"需要證明的，不是我們，而是你們吧？還需要我來告訴你們處於什麼立場嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야, 에이미……!","JPN":"ちょっと、エイミー……！","ENG":"Amy, enough...!","TWN":"喂，艾米！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 입장이라…….","JPN":"ふふ、立場か……","ENG":"Haha, \\"where we stand,\\" huh...","TWN":"呵呵，立場嗎？？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 한 가지 묻도록 하지, 킬 미 레이디.","JPN":"では一つ聞くとしよう、キル・ミー・レディー。","ENG":"Then let me ask you something, Kill Me Lady.","TWN":"那麼，我來問你一個問題，殺手小姐。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네 말대로 나와 스완이 정말로 애절한 연인 관계였다고 가정해 보자고.","JPN":"君の言うとおり、私とスワンが本当に切ない恋人関係であったと仮定してみよう。","ENG":"Let's say, for argument's sake, Swan and I really were tragically in love.","TWN":"就像你說的，假設我和史旺真的是一對深情的戀人吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애, 애버라인……!","JPN":"あ、アバーライン……！","ENG":"A-Abberline...!","TWN":"艾、艾伯林！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 결국 심야의 살인마 사건을 막지 못했고, 우리의 세계는 멸망해 버렸어.","JPN":"私たちは結局深夜の殺人鬼事件を阻止できず、世界は滅亡してしまった。","ENG":"We failed to stop the Midnight Killer, and our world was destroyed.","TWN":"我們最終沒能阻止午夜殺人魔事件，我們的世界已經滅亡了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"오랜 시간이 지나, 미래의 스완은 어찌저찌 세계를 되돌릴 힘을 손에 넣었고.","JPN":"長い時が過ぎ、未来のスワンはどうにかして世界を元に戻す力を手に入れ。","ENG":"Years later, Swan gains the power to restore her world.","TWN":"經過漫長的時間，未來的史旺終於獲得了扭轉世界的力量。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사랑하는 연인인 나를 되살리기 위해, 이 세계를 되돌렸다… 그렇게 주장할 셈이겠지?","JPN":"恋人である私を蘇らせるため、この世界を元に戻した……そう主張するつもりなのだろう？","ENG":"And to bring her beloved back, she does it... That's your theory, isn't it?","TWN":"為了復活深愛著的我，才將這個世界逆轉……你是打算這樣主張嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사, 사랑……!?","JPN":"恋……！？","ENG":"B-beloved...?!","TWN":"愛、愛！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 왜 하필 지금일까?","JPN":"では、なぜ今なのだろう？","ENG":"Then why now of all times?","TWN":"那為什麼偏偏是現在呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"は？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네들이 말하는 그 세피라라는 게 어떤 식으로 작용하는 힘인지는 잘 모르겠지만.","JPN":"君たちの言う、そのセフィラというものがどういう風に作用する力なのかはわからないが。","ENG":"I don't know how this Sephira you talk about works.","TWN":"雖然我不太清楚你們所說的那個生命樹是如何運作力量的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계는 이미 임계치에 다다라 멸망을 앞둔 세계야.","JPN":"この世界はすでに臨界値に達し、滅亡が目前にある。","ENG":"But this world's already at its limit. On the brink of collapse.","TWN":"但這個世界已經達到了臨界點，正面臨著滅亡。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마 사건을 막는다고 하더라도… 언제, 어떻게 멸망해도 이상하지 않아.","JPN":"深夜の殺人鬼事件を阻止できたとしても……いつ、どう滅亡してもおかしくない。","ENG":"Even if we stop the Midnight Killer, nothing guarantees it won't still fall apart.","TWN":"即使我們阻止了午夜殺人魔，也不能保證一切不會崩壞。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 지금보다 훨씬 더 이전으로 세계를 돌릴 수도 있지 않았을까?","JPN":"ならば、今よりももっと過去の世界に戻せば良かったのではないか？","ENG":"So why not restore the world even further back in time, before things got this bad?","TWN":"那麼，難道不能把世界倒回到更早以前嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"만약 나에게 모든 걸 돌이킬 수 있는 힘이 있다면, 나는 그렇게 했을 걸세.","JPN":"もし私に全てを取り戻すことができる力があるなら、私はそうしたはずだ。","ENG":"If I had the power to undo everything, I would've done that.","TWN":"如果我有能力讓一切重來，我會那樣做的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"……쳇.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"나도 몰라! 스완의 음습한 속내를 내가 어떻게 알겠어?","JPN":"あたしだって知らないよ！　腹黒いスワンの考えなんてさ！","ENG":"I don't know! How should I know what that conniving witch is thinking?","TWN":"我也不知道！我怎麼會知道史旺陰暗的內心呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으, 음습한… 속내라고요……!?","JPN":"は、腹黒い……！？","ENG":"C-conniving...?!","TWN":"呃，陰暗的……內心嗎！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"듣자 듣자 하니 이젠 정말로 못 들어주겠군요!","JPN":"黙って聞いていれば、あなたたちは！　もうたくさんです！","ENG":"I've had just about enough of this!","TWN":"我真的聽不下去了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"몇 번이나 말했잖아요! 저랑 저 능글맞은 남자는 아무런 사이도 아니라니까……!","JPN":"何度も言ったはずです！　私とあの図々しい男はそんな関係ではありません……！","ENG":"I've told you again and again! I have nothing going on with that slippery snake of a man...!","TWN":"我都說了多少遍了！我和那個油腔滑調的傢伙什麼關係都沒有！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"중상모략도 이런 중상모략이 없네요!","JPN":"誹謗中傷にもほどがあります！","ENG":"This is the worst kind of slander!","TWN":"這是最惡劣的誹謗！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계가 이미 멸망했고… 미래의 제가 이곳에 되돌아와서 멸망한 세계를 되돌렸다고요……?","JPN":"この世界がすでに滅亡して……未来の私がここに帰って、滅亡した世界を元に戻した……？","ENG":"The world has already come to an end... and will the future me comes back to reverse it...?","TWN":"這個世界已經毀滅了……未來的我回到了這裡，挽救了這個毀滅的世界？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그 이유가 고작 저 오지랖 넓은 능구렁이 때문이라고……?","JPN":"そしてその理由が、あのお節介な古狸のためですって……？","ENG":"And all for the sake of that nosy creep...?","TWN":"而且原因竟然只是因為那個多管閒事的老狐狸？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 웃기지 말라고요!","JPN":"もう！　ふざけないでください！","ENG":"Oh please, don't make me laugh!","TWN":"真是的！別開玩笑了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 사실이라면, 미래의 저는 남자 뒤꽁무니나 따라다니는 한심한 여자가 틀림없겠군요……!","JPN":"それが本当なら、未来の私はきっと男の尻を追う情けない女です……！","ENG":"If that's true, then future me is just some pathetic girl who trails after men...!","TWN":"如果那是真的，那麼未來的我一定是個只會跟在男人屁股後面跑的可憐女人！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"런던 제일의 프리마돈나, 스완 클레어라는 이름이 울겠어요!","JPN":"ロンドン一のプリマドンナ、スワン・クレアの名が泣きますね！","ENG":"The name Swan Claire, London's top prima donna, would be a joke!","TWN":"倫敦第一的女主角，史旺·克萊爾這個名字都要哭了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥……!!","JPN":"ふんっ……！！","ENG":"Hmph...!!","TWN":"哼……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"푸흡…! 크하하하하하하하핫……!","JPN":"ぷうっ……！　あははははははははっ……！","ENG":"Pfft...! Ahahahahahahaha...!","TWN":"噗！？哈哈哈哈哈哈！？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜 비웃는 거야! 이 천박한 이방인……!","JPN":"どうして笑うのよ！　この下品な異邦人……！","ENG":"Why are you laughing?! You crass little outsider...!","TWN":"你為什麼笑我！這個粗俗的外邦人……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭. 이것조차 연기라면, 그건 그것대로 가관이겠네.","JPN":"くくっ。これも演技だってなら、それはそれで見物だな。","ENG":"Keke. If that was an act, it was a pretty impressive one.","TWN":"呵呵。如果這也是演技的話，那也真是精彩絕倫呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어린애 놀리는 건 그쯤 해 두라고.","JPN":"子どもをからかうのはそれくらいにしておきなよ。","ENG":"That's enough teasing the kid.","TWN":"逗小孩子就到此為止吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 설마 그 차갑고 냉혹하던 스완이 어렸을 때는 이런 성격이었을 줄이야…….","JPN":"でも、まさかあの冷たくて冷酷だったスワンが、小さい頃はこんな性格だったなんて……","ENG":"But I never would've guessed the cold, ruthless Swan was this kind of kid back then...","TWN":"不過沒想到那個冷酷無情的史旺，小時候竟然是這樣的性格……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아아~ 의심했던 건 취소, 취소야.","JPN":"ああ～、疑ったのはなしだ、なし。","ENG":"Okay, okay. I take it back.","TWN":"好，好，我收回剛才的話。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이 정도 긁었는데 안 넘어오는 거 보면, 이 꼬맹이는 우리가 찾는 스완이 아니겠지.","JPN":"ここまで挑発したのに乗らないってことは、このガキはあたしらが探してるスワンじゃないんだろう。","ENG":"After all that provocation, if she's still standing her ground, then this brat isn't the Swan we're after.","TWN":"經過那麼多挑釁，如果她還能堅持立場，那麼這個小鬼就不是我們要找的史旺。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 이제 다시 원점으로 돌아온 건가?","JPN":"さて、また振り出しに戻ったのかな？","ENG":"So I guess we're back to square one?","TWN":"那麼，現在又回到原點了嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"원점이라…….","JPN":"振り出しか……","ENG":"Square one...","TWN":"回到原點……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미, 나는 역시 이 탐정 아저씨 말이 걸려.","JPN":"エイミー、私はやっぱりこの探偵のおじさんの話がひっかかるんだ。","ENG":"Amy, I still can't get that detective's words out of my head.","TWN":"艾米，我還是很在意這個偵探先生的話。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜 스완은 하필 이 타이밍을 골라서 자기 세계를 과거로 되돌린 걸까?","JPN":"どうしてスワンは自分の世界を、よりによってこのタイミングに戻したんだろう？","ENG":"Why would Swan pick this exact moment to restore her world?","TWN":"為什麼史旺偏偏選擇在這個時機將自己的世界回溯到過去呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이래서야 결국 똑같은 사건을 되풀이하게 될 뿐이잖아?","JPN":"これじゃあ、結局同じ事件を繰り返すだけじゃない。","ENG":"This way, she's just setting herself up to repeat the same events, isn't she?","TWN":"這樣下去，最終只會重蹈覆轍吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 이런 게 무슨 의미가 있다는 거야?","JPN":"いったいこれに何の意味があるのかな？","ENG":"What's the point of that?","TWN":"這到底有什麼意義呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐……?","JPN":"待て……","ENG":"Hold on...","TWN":"等一下？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"방금, 자네 뭐라고 했나…? 똑같은 사건을 <color=#ffd34c>되풀이</color>한다고……?","JPN":"君、今なんと言ったのかね……？　同じ事件を<color=#ffd34c>繰り返す</color>……？","ENG":"What did you just say...? <color=#ffd34c>Repeat</color> the same events...?","TWN":"你剛才說什麼？說會<color=#ffd34c>重蹈覆轍</color>?"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 어어……?","JPN":"えっ？　う、うん。","ENG":"Huh? U-uh...?","TWN":"啊？啊啊？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 무서운 표정으로 왜 그래, 탐정 아저씨?","JPN":"いきなり怖い顔してどうしたの、探偵のおじさん？","ENG":"Why the scary face all of a sudden, Mr. Detective?","TWN":"幹嘛突然露出那麼嚇人的表情，偵探先生？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭔가 떠오른 거야?","JPN":"何かわかった？","ENG":"Did something come to mind?","TWN":"是想起來什麼嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 아무것도 아니라네.","JPN":"いや、なんでもない。","ENG":"No, it's nothing.","TWN":"不，沒什麼？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"흥, 뭐야, 싱겁긴……!","JPN":"ふん、なんだよ、シラケるな……！","ENG":"Hmph. What a letdown...!","TWN":"哼，什麼嘛？真無趣！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 이쯤에서 자네들에게 한 가지 제안을 하고 싶은데.","JPN":"それより、ここで君たちに一つ提案があるのだが。","ENG":"More importantly, there's something I'd like to propose to you all.","TWN":"比起這個，我想向你們提出一個提議。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제안이라고?","JPN":"提案？","ENG":"A proposal?","TWN":"提議？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 서로에게 이득이 되는 제안이라네.","JPN":"もちろん、お互いに得する提案だ。","ENG":"One that benefits each other.","TWN":"當然，這是一個對雙方都有利的提議。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네들 말이 전부 사실이라면, 범인은 이 시점으로 세계를 되돌린 이유가 있을 거야.","JPN":"君たちの話が全て事実なら、犯人はこの時点に世界を戻した理由があるはずだ。","ENG":"If what you're saying is true, then there's a reason the culprit brought the world back to this point.","TWN":"如果你們說的都是真的，那麼兇手將世界倒回到這個時間點一定有他的理由。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 틀림없이 심야의 살인마 사건과 관계가 있겠지.","JPN":"それは間違いなく、深夜の殺人鬼事件と関係があるだろう。","ENG":"And I'm sure it's tied to the Midnight Killer case.","TWN":"那肯定和午夜殺人魔事件有關吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리의 목적은 심야의 살인마가 이 도시에서 벌이려는 의식을 저지하는 것이라네.","JPN":"私たちの目的は深夜の殺人鬼がこの都市で行おうとしている儀式を阻止すること。","ENG":"Our goal is to stop the ritual the Midnight Killer is planning in this city.","TWN":"我們的目的是阻止午夜殺人魔要在這座城市進行的儀式。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 우선은 자네들도 사건 수사에 협조하는 게 어떻겠나?","JPN":"だから、まずは君たちも事件の捜査に協力するのはどうかね？","ENG":"So why not cooperate with the investigation, at least for now?","TWN":"所以不如你們也先協助調查案件怎麼樣？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마침, <color=#ffd34c>결행일</color>이 얼마 남지 않았거든.","JPN":"ちょうど、<color=#ffd34c>決行日</color>が近いことだしな。","ENG":"We're running out of time. The <color=#ffd34c>day of the ritual</color> is fast approaching.","TWN":"正好，<color=#ffd34c>行動日</color>快到了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"결행일이라고……?","JPN":"決行日……？","ENG":"The day of the ritual...?","TWN":"行動日？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 결행일은 앞으로 사흘 뒤…….","JPN":"ああ。決行日は3日後……","ENG":"Yes. It's in three days...","TWN":"是的。行動日是三天後……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 런던에서 벌어지고 있는 심야의 살인마 사건, 그 배후에 있는 존재…….","JPN":"今ロンドンで起こっている深夜の殺人鬼事件、その背後にいる存在……","ENG":"That's the day we finally capture the man behind the Midnight Killer case...","TWN":"是抓捕現在倫敦正在發生的午夜殺人魔事件，其背後的主使……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"제임스 모리어티 교수를 체포하는 날이라네.","JPN":"ジェームス・モリアーティ教授を逮捕する日だ。","ENG":"The day Professor James Moriarty gets arrested.","TWN":"詹姆斯·莫里蒂教授的日子。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};